Looks great to me! Two questions about the cleanup gRPC cleanup routine. 

I'd recommend trying to manually validate (probably don't need to add a full test) one additional error case. The failure mode for gRPC requests and the provider chain is a little more complicated to reason about. A program like this will fail without the GCP project and zone set. Might be work running the equivalent in python just to make sure the error is caught and the automation script terminates gracefully (no hangs);

```ts
const run = async () => {
    // This is our pulumi program in "inline function" form
    const pulumiProgram = async () => {
        // this call fails if gcp:project and gcp:zone are not set. 
        const engineVersion = gcp.container.getEngineVersions().then((v) => v.latestMasterVersion);
        return {
            engv: engineVersion
        };
    };

    // Create our stack 
    const args: InlineProgramArgs = {
        stackName: "dev1",
        projectName: "inlineNode",
        program: pulumiProgram
    };

    // create (or select if one already exists) a stack that uses our inline program
    const stack = await LocalWorkspace.createOrSelectStack(args);

    console.info("updating stack...");
    try {
        const upRes = await stack.up({ onOutput: console.info });
        console.log(`update summary: \n${JSON.stringify(upRes.summary.resourceChanges, null, 4)}`);
    }
    catch (e){
        console.log(e)
        process.exit(1)
    }
};

run().catch(err => {
    console.log("there was an error")
    console.log(err)
    console.log("error logged")
});
```

